const sqlite3 = require('sqlite3').verbose(); const db = new sqlite3.Database('./db.sqlite'); db.all('SELECT * FROM users', [], (err, rows) => { if (err) { console.error('Error querying users:', err); return; } console.log('Users:', JSON.stringify(rows, null, 2)); db.all('SELECT * FROM roles', [], (err, roles) => { if (err) { console.error('Error querying roles:', err); return; } console.log('Roles:', JSON.stringify(roles, null, 2)); db.close(); }); });
